var vi = require('fs').readFileSync('vi.html', 'utf-8');

// The pricelist market-group is generated by JS (h += ...)
// Let me find which module generates it
var idx = vi.indexOf('class="market-group"');
// Go backwards to find the function boundary
var before = vi.substring(Math.max(0, idx-5000), idx);
// Find the last function definition before this
var lastFn = before.lastIndexOf('function renderPriceTab');
if (lastFn < 0) lastFn = before.lastIndexOf('function render');
console.log('Last function:', lastFn >= 0 ? vi.substring(lastFn, lastFn+40) : 'none');
// Also check if it's in the template (set by build process)
// Let me search template.html for the market-group HTML
var tpl = require('fs').readFileSync('src/template.html', 'utf-8');
var tplIdx = tpl.indexOf('id="marketCn"');
console.log('template.html has marketCn:', tplIdx >= 0);
if (tplIdx >= 0) {
  console.log('Template marketCn at', tplIdx, tpl.substring(tplIdx-100, tplIdx+100));
}
// Check build.js to see if template is directly used
var build = require('fs').readFileSync('build.js', 'utf-8');
var tplRepl = build.indexOf('tpl.replace');
console.log('build.js template replacements:');
var pos = 0;
while (pos >= 0) {
  pos = build.indexOf('tpl.replace', pos);
  if (pos < 0) break;
  console.log('  ->', build.substring(pos, pos+100));
  pos++;
}
